<?php
declare(strict_types=1);

function legal_default_privacy():string{$company=app_setting('legal_company_name')?:app_setting('app_name','OpenCRM');$email=app_setting('legal_contact_email')?:app_setting('mail_from_address');return $company.' collects contact information you provide, form and booking details, CRM activity, and privacy-conscious website analytics. We use this information to respond to requests, provide requested resources and services, manage business relationships, improve our services, prevent abuse, and meet legal obligations. We do not sell personal information. Authorized service providers may process data for hosting, email, scheduling, analytics, AI-assisted content, and payments. You may request access, correction, deletion, or withdrawal of marketing consent by contacting '.$email.'. '.app_setting('legal_retention_policy');}
function legal_default_terms():string{return 'These services are provided by '.(app_setting('legal_company_name')?:app_setting('app_name','OpenCRM')).'. You may use public forms, resources, booking pages, and published content only for lawful purposes. Do not attempt unauthorized access, interfere with service operation, submit malicious content, or misuse intellectual property. Published information is provided for general business purposes and may change without notice. To the maximum extent permitted by law, services and content are provided as is without warranties, and liability is limited as permitted by applicable law. Contact '.(app_setting('legal_contact_email')?:app_setting('mail_from_address')).' with questions.';}
function legal_footer_html():string{$privacy=rtrim((string)config('url'),'/').'/legal/privacy';$terms=rtrim((string)config('url'),'/').'/legal/terms';$company=app_setting('legal_company_name')?:app_setting('app_name','OpenCRM');return '<footer style="margin:32px auto;padding:18px;max-width:1100px;text-align:center;font:14px/1.5 Arial,sans-serif;color:#607d8b;border-top:1px solid #ddd">&copy; '.date('Y').' '.e($company).' &middot; <a href="'.e($privacy).'">Privacy Policy</a> &middot; <a href="'.e($terms).'">Terms of Use</a></footer>';}
function legal_inject_footer(string $html):string{if(!str_contains(strtolower($html),'</body>'))return $html;$insert=legal_footer_html();if(preg_match('#^/f/[a-z0-9_-]+$#',(string)($GLOBALS['path']??''))&&str_contains($html,'public-form')){$disclosure='<div class="legal-consent" style="margin:16px 0;font-size:14px"><p>'.e(app_setting('legal_form_disclosure')).' <a href="/legal/privacy" target="_blank">Privacy Policy</a> and <a href="/legal/terms" target="_blank">Terms of Use</a>.</p><label><input type="checkbox" name="marketing_consent" value="1" style="width:auto"> '.e(app_setting('legal_marketing_consent')).'</label>';if(app_setting('legal_require_form_consent')==='1')$disclosure.='<label><input type="checkbox" name="legal_consent" value="1" style="width:auto" required> I acknowledge the Privacy Policy and Terms of Use.</label>';$disclosure.='</div>';$html=preg_replace('/<\/form>/',$disclosure.'</form>',$html,1);}$html=str_ireplace('</body>',$insert.'</body>',$html);return $html;}

if(preg_match('#^/legal/(privacy|terms)$#',$path,$m)){$privacy=$m[1]==='privacy';$title=$privacy?'Privacy Policy':'Terms of Use';$body=$privacy?(app_setting('legal_privacy_policy')?:legal_default_privacy()):(app_setting('legal_terms_of_use')?:legal_default_terms());header('Content-Type:text/html;charset=UTF-8');?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=e($title)?> · <?=e(app_setting('app_name','OpenCRM'))?></title><link rel="stylesheet" href="/assets/app.css"></head><body><main class="container"><article class="card"><h1><?=e($title)?></h1><p class="muted">Last updated <?=e(app_setting('legal_updated_at',date('F j, Y')))?></p><?=nl2br(e($body))?><hr><p><strong>Contact</strong><br><?=nl2br(e(app_setting('legal_company_name')?:app_setting('app_name','OpenCRM')))?><?php if(app_setting('legal_company_address')):?><br><?=nl2br(e(app_setting('legal_company_address')))?><?php endif?><?php if(app_setting('legal_contact_email')):?><br><a href="mailto:<?=e(app_setting('legal_contact_email'))?>"><?=e(app_setting('legal_contact_email'))?></a><?php endif?></p></article></main><?=legal_footer_html()?></body></html><?php exit;}

if($path==='/admin/legal'){require_login();if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}if($method==='POST'){verify_csrf();$email=trim((string)post('legal_contact_email'));if($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL)){flash('error','Enter a valid legal contact email.');redirect('/admin/legal');}$keys=['legal_company_name','legal_contact_email','legal_company_address','legal_privacy_policy','legal_terms_of_use','legal_cookie_notice','legal_marketing_consent','legal_retention_policy','legal_form_disclosure'];$save=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($keys as $key)$save->execute([$key,trim((string)post($key))]);$save->execute(['legal_require_form_consent',post('legal_require_form_consent')?'1':'0']);$save->execute(['legal_updated_at',date('F j, Y')]);audit('update','legal_settings');flash('success','Legal and consent settings saved.');redirect('/admin/legal');}$s=app_settings();layout('Legal and privacy settings',function()use($s){?><h1>Legal, privacy, and consent</h1><div class="card"><p><strong>Important:</strong> These editable templates are operational starting points, not legal advice. Have qualified counsel review them for your jurisdictions, industry, and actual data practices.</p><p><a href="/legal/privacy" target="_blank">Preview Privacy Policy</a> · <a href="/legal/terms" target="_blank">Preview Terms of Use</a></p></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Legal company name<input name="legal_company_name" value="<?=e($s['legal_company_name']?:$s['app_name'])?>" required></label><label>Privacy contact email<input type="email" name="legal_contact_email" value="<?=e($s['legal_contact_email']?:$s['mail_from_address'])?>" required></label><label class="full">Company mailing address<textarea name="legal_company_address" placeholder="Required in many commercial email jurisdictions"><?=e($s['legal_company_address'])?></textarea></label></div><label>Privacy Policy<textarea name="legal_privacy_policy" rows="12"><?=e($s['legal_privacy_policy']?:legal_default_privacy())?></textarea></label><label>Terms of Use<textarea name="legal_terms_of_use" rows="12"><?=e($s['legal_terms_of_use']?:legal_default_terms())?></textarea></label><label>Cookie/analytics notice<textarea name="legal_cookie_notice" rows="3"><?=e($s['legal_cookie_notice'])?></textarea></label><label>Marketing consent language<textarea name="legal_marketing_consent" rows="3"><?=e($s['legal_marketing_consent'])?></textarea></label><label>Data-retention statement<textarea name="legal_retention_policy" rows="4"><?=e($s['legal_retention_policy'])?></textarea></label><label>Public-form disclosure<textarea name="legal_form_disclosure" rows="3"><?=e($s['legal_form_disclosure'])?></textarea></label><label><input type="checkbox" name="legal_require_form_consent" value="1" style="width:auto" <?=$s['legal_require_form_consent']==='1'?'checked':''?>> Require explicit Privacy/Terms acknowledgement on public CRM forms</label><button>Save legal settings</button></form><?php });exit;}

if(preg_match('#^/(?:f|s|book|resource-library|quote|published/lead-magnet|email/unsubscribe)/#',$path)){
    if($method==='POST'&&preg_match('#^/f/[a-z0-9_-]+$#',$path)&&app_setting('legal_require_form_consent')==='1'&&empty($_POST['legal_consent'])){http_response_code(422);header('Content-Type:text/html;charset=UTF-8');?><!doctype html><html><head><meta name="viewport" content="width=device-width"><link rel="stylesheet" href="/assets/app.css"></head><body><main class="container"><div class="card"><h1>Consent required</h1><p>Please go back and acknowledge the Privacy Policy and Terms of Use before submitting.</p><button onclick="history.back()">Go back</button></div></main><?=legal_footer_html()?></body></html><?php exit;}
    ob_start(fn(string $html):string=>str_replace('We use privacy-conscious analytics to understand visits and improve this site.',e(app_setting('legal_cookie_notice')),legal_inject_footer($html)));
    if($method==='POST'&&preg_match('#^/f/([a-z0-9_-]+)$#',$path,$match)){$before=(int)db()->query('SELECT COALESCE(MAX(id),0) FROM crm_form_submissions')->fetchColumn();$marketing=!empty($_POST['marketing_consent']);register_shutdown_function(function()use($before,$match,$marketing){try{$q=db()->prepare('SELECT fs.contact_id FROM crm_form_submissions fs JOIN crm_forms f ON f.id=fs.form_id WHERE fs.id>? AND f.slug=? ORDER BY fs.id DESC LIMIT 1');$q->execute([$before,$match[1]]);$contactId=(int)$q->fetchColumn();if(!$contactId)return;$token=bin2hex(random_bytes(32));db()->prepare("INSERT INTO contact_email_preferences(contact_id,status,consent_source,consent_at,unsubscribe_token) VALUES(?,?,?,?,?) ON DUPLICATE KEY UPDATE status=VALUES(status),consent_source=VALUES(consent_source),consent_at=VALUES(consent_at)")->execute([$contactId,$marketing?'subscribed':'transactional_only',$marketing?'public_form':'no_marketing_consent',$marketing?date('Y-m-d H:i:s'):null,$token]);}catch(Throwable $e){app_log('error','Form consent recording failed',['error'=>$e->getMessage()]);}});}
}

